namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public static class RecipeData
{
    public static List<string> Categories { get; } =
    [
        "Breakfast",
        "Lunch",
        "Dinner",
        "Desserts",
        "Snacks",
        "Beverages"
    ];

    public static List<Recipe> Recipes { get; } =
    [
        new Recipe
        {
            Id = 1, Title = "Fluffy Pancakes", Category = "Breakfast",
            Ingredients = "2 cups flour\n2 eggs\n1 cup milk\n2 tbsp sugar\n1 tsp baking powder\nButter for cooking",
            Steps = "1. Mix dry ingredients together.\n2. Whisk eggs and milk, then combine with dry mix.\n3. Heat a buttered pan over medium heat.\n4. Pour batter and cook until bubbles form, then flip.\n5. Serve with maple syrup.",
            AverageRating = 4.5, RatingCount = 12
        },
        new Recipe
        {
            Id = 2, Title = "Classic BLT Sandwich", Category = "Lunch",
            Ingredients = "2 slices bread\n4 strips bacon\nLettuce leaves\n2 tomato slices\nMayonnaise",
            Steps = "1. Cook bacon until crispy.\n2. Toast bread slices.\n3. Spread mayo on toast.\n4. Layer lettuce, tomato, and bacon.\n5. Close sandwich and serve.",
            AverageRating = 4.2, RatingCount = 8
        },
        new Recipe
        {
            Id = 3, Title = "Garlic Butter Pasta", Category = "Dinner",
            Ingredients = "400g spaghetti\n4 cloves garlic\n3 tbsp butter\nParmesan cheese\nFresh parsley\nSalt and pepper",
            Steps = "1. Cook pasta according to package directions.\n2. Melt butter in a pan, sauté minced garlic.\n3. Toss drained pasta in garlic butter.\n4. Season with salt and pepper.\n5. Top with parmesan and parsley.",
            AverageRating = 4.8, RatingCount = 20
        },
        new Recipe
        {
            Id = 4, Title = "Chocolate Lava Cake", Category = "Desserts",
            Ingredients = "200g dark chocolate\n100g butter\n2 eggs\n2 egg yolks\n50g sugar\n2 tbsp flour",
            Steps = "1. Melt chocolate and butter together.\n2. Whisk eggs, yolks, and sugar until thick.\n3. Fold chocolate mixture into eggs, then add flour.\n4. Pour into greased ramekins.\n5. Bake at 220°C for 12 minutes.\n6. Invert onto plates and serve immediately.",
            AverageRating = 4.9, RatingCount = 15
        },
        new Recipe
        {
            Id = 5, Title = "Guacamole", Category = "Snacks",
            Ingredients = "3 ripe avocados\n1 lime\n1 tsp salt\n½ cup onion, diced\n3 tbsp fresh cilantro\n2 roma tomatoes\n1 tsp garlic",
            Steps = "1. Mash avocados in a bowl.\n2. Stir in lime juice and salt.\n3. Mix in onion, cilantro, tomatoes, and garlic.\n4. Refrigerate for 1 hour before serving.\n5. Serve with tortilla chips.",
            AverageRating = 4.3, RatingCount = 10
        },
        new Recipe
        {
            Id = 6, Title = "Iced Matcha Latte", Category = "Beverages",
            Ingredients = "2 tsp matcha powder\n2 tbsp hot water\n1 cup milk\nIce cubes\nHoney or sweetener (optional)",
            Steps = "1. Sift matcha powder into a bowl.\n2. Add hot water and whisk until smooth.\n3. Fill a glass with ice.\n4. Pour milk over ice.\n5. Add matcha mixture on top.\n6. Stir and sweeten to taste.",
            AverageRating = 4.1, RatingCount = 6
        }
    ];
}

@rendermode InteractiveServer

<div class="star-rating">
    <span class="rating-label">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= currentRating ? "filled" : "")"
              @onclick="() => SetRating(star)"
              title="@star star(s)">
            @(star <= currentRating ? "★" : "☆")
        </span>
    }
    @if (hasRated)
    {
        <span class="rating-thanks">Thanks! You rated @currentRating/5</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int currentRating;
    private bool hasRated;

    protected override void OnParametersSet()
    {
        if (!hasRated)
        {
            currentRating = (int)Math.Round(AverageRating);
        }
    }

    private void SetRating(int rating)
    {
        currentRating = rating;
        hasRated = true;
    }
}

@page "/recipes/{Category}"
@using RecipeCommunity.Models

<PageTitle>@Category Recipes - Recipe Community</PageTitle>

<h2>@Category Recipes</h2>

<div class="row">
    @foreach (var recipe in GetRecipes())
    {
        <div class="col-md-6 col-lg-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@recipe.Title</h5>
                    <p class="card-text text-muted">
                        ★ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                    </p>
                    <a href="/recipes/detail/@recipe.Id" class="btn btn-primary">View Recipe</a>
                </div>
            </div>
        </div>
    }
</div>

@if (!GetRecipes().Any())
{
    <p class="text-muted">No recipes found in this category yet.</p>
}

<a href="/" class="btn btn-outline-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter] public string Category { get; set; } = string.Empty;

    private List<Recipe> GetRecipes() =>
        RecipeData.Recipes.Where(r => r.Category.Equals(Category, StringComparison.OrdinalIgnoreCase)).ToList();
}

@page "/recipes/detail/{Id:int}"
@using RecipeCommunity.Models
@using RecipeCommunity.Components.Shared

<PageTitle>@(recipe?.Title ?? "Recipe") - Recipe Community</PageTitle>

@if (recipe is not null)
{
    <h2>@recipe.Title</h2>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <div class="row mt-3">
        <div class="col-md-5">
            <div class="card">
                <div class="card-header"><strong>Ingredients</strong></div>
                <div class="card-body">
                    <ul class="mb-0">
                        @foreach (var ingredient in recipe.Ingredients.Split('\n'))
                        {
                            <li>@ingredient</li>
                        }
                    </ul>
                </div>
            </div>
        </div>
        <div class="col-md-7">
            <div class="card">
                <div class="card-header"><strong>Instructions</strong></div>
                <div class="card-body">
                    @foreach (var step in recipe.Steps.Split('\n'))
                    {
                        <p class="mb-1">@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="mt-4 p-3 border rounded">
        <StarRating RecipeId="@recipe.Id"
                    AverageRating="@recipe.AverageRating"
                    RatingCount="@recipe.RatingCount" />
    </div>

    <a href="/recipes/@recipe.Category" class="btn btn-outline-secondary mt-3">← Back to @recipe.Category</a>
}
else
{
    <h3>Recipe not found</h3>
    <a href="/" class="btn btn-outline-secondary">← Back to Home</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeData.Recipes.FirstOrDefault(r => r.Id == Id);
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<h2>Submit a Recipe</h2>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Thank you for sharing "<strong>@model.Title</strong>" with the community.</p>
        <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="recipeForm">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="model.Category">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeCommunity.Models.RecipeData.Categories)
                {
                    <option value="@cat">@cat</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="model.Ingredients"
                           placeholder="One ingredient per line" />
            <ValidationMessage For="() => model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="model.Steps"
                           placeholder="Describe each step..." />
            <ValidationMessage For="() => model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel model = new();
    private bool submitted;

    private void HandleSubmit()
    {
        submitted = true;
    }

    private void Reset()
    {
        model = new();
        submitted = false;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        [System.ComponentModel.DataAnnotations.StringLength(100)]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required")]
        public string Steps { get; set; } = string.Empty;
    }
}

